import "google/protobuf/timestamp.proto";
import "google/protobuf/duration.proto";
import "google/protobuf/field_mask.proto";

message Order {
  string order_id = 1;                       // bytes if truly opaque/binary
  int64 total_amount_minor_units = 2;         // cents -- never float/double for money
  string currency_code = 3;                   // e.g. "USD", ISO 4217

  google.protobuf.Timestamp placed_at = 4;
  google.protobuf.Duration fulfillment_sla = 5;

  enum Status {
    STATUS_UNSPECIFIED = 0;
    PENDING = 1;
    SHIPPED = 2;
    DELIVERED = 3;
    CANCELLED = 4;
  }
  Status status = 6;

  map<string, string> labels = 7;              // string/string metadata -- fine

  message LineItem {
    string sku = 1;
    int32 quantity = 2;
    optional string gift_note = 3;             // per-element presence
  }
  repeated LineItem line_items = 8;
}

message UpdateOrderRequest {
  Order order = 1;
  google.protobuf.FieldMask update_mask = 2;   // "status", "line_items" ...
}

message Product {
  // v1 shipped: name=1, quantity=2, sku_legacy=3

  string name = 1;
  int32 quantity = 2;

  reserved 3;
  reserved "sku_legacy";   // deleted; number 3 and the old name can never come back

  optional string description = 4;   // added in v2 -- old readers just skip it

  string internal_note = 5 [deprecated = true];   // still on the wire; new code shouldn't set it
}

message Payment {
  // exactly one funding source is set
  oneof source {
    CardDetails card = 1;
    BankTransfer bank = 2;
    string wallet_id = 3;
  }
  int64 amount_cents = 10;   // NOT in the oneof — always present
}

