syntax = "proto3";
package mycorp.billing.v1;   // versioned namespace so v2 can coexist

option go_package = "mycorp/billing/v1;billingv1";
option java_package = "com.mycorp.billing.v1";

// Every RPC gets its own wrapper, even the 'simple' ones.
rpc ListInvoices(ListInvoicesRequest) returns (ListInvoicesResponse);

message ListInvoicesRequest {
  string customer_id = 1;
  int32  page_size   = 2;   // designed in up front
  string page_token  = 3;   // opaque cursor from a previous response
}
message ListInvoicesResponse {
  repeated Invoice invoices = 1;
  string next_page_token = 2;   // empty when iteration is done
}

import "google/protobuf/any.proto";

message AuditEvent {
  string actor = 1;
  google.protobuf.Any payload = 2;  // type_url + serialized bytes
}

// Prefer a closed oneof when the variants are KNOWN:
message AuditEventClosed {
  string actor = 1;
  oneof payload {
    LoginEvent  login  = 2;
    LogoutEvent logout = 3;
    PurchaseEvent purchase = 4;
  }
}

syntax = "proto3";
package routeguide.v1;

service RouteGuide {
  // Unary: one request, one response.
  rpc GetFeature(Point) returns (Feature);

  // Server streaming: one request, a stream of responses.
  rpc ListFeatures(Rectangle) returns (stream Feature);

  // Client streaming: a stream of requests, one response.
  rpc RecordRoute(stream Point) returns (RouteSummary);

  // Bidirectional streaming: two independent streams.
  rpc RouteChat(stream RouteNote) returns (stream RouteNote);
}

syntax = "proto3";
package catalog.v1;

import "google/protobuf/timestamp.proto";

enum Availability {
  AVAILABILITY_UNSPECIFIED = 0;
  AVAILABILITY_IN_STOCK    = 1;
  AVAILABILITY_BACKORDER   = 2;
}

message Product {
  int64  sku          = 1;   // 64-bit id
  string display_name = 2;
  Availability status  = 3;
  bytes  thumbnail     = 4;
  google.protobuf.Timestamp updated_at = 5;
}

// The SAME field, four ways generators render it:
// proto:   int64 sku = 1;
// Go:      Sku int64          // m.GetSku()
// Java:    long getSku()      // builder.setSku(long)
// Python:  product.sku        // an int attribute
// C#:      long Sku { get; set; }

// conformance.proto — how every implementation is interop-tested:
message ConformanceRequest {
  oneof payload {
    bytes  protobuf_payload = 1;
    string json_payload     = 2;
  }
  WireFormat requested_output_format = 3;
  string     message_type            = 4;
}
message ConformanceResponse {
  oneof result {
    string parse_error      = 1;
    string serialize_error  = 6;
    bytes  protobuf_payload = 3;
    string json_payload     = 4;
    string skipped          = 5;
  }
}
enum WireFormat { UNSPECIFIED = 0; PROTOBUF = 1; JSON = 2; JSPB = 3; TEXT_FORMAT = 4; }

message Order {
  string id = 1;
  // v1: total in cents as int32. v2 widens to int64.
  // WIRE-compatible, but an un-upgraded 32-bit reader TRUNCATES
  // values > 2^31-1 -> keep emitted totals in range until all
  // readers are upgraded.
  int64 total_cents = 2;

  string coupon_code = 3 [deprecated = true];  // gradual retirement signal
  reserved 4;                                   // a number we deleted, never to reuse
  reserved "legacy_status";
}

// Arena allocation (C++): one bump-allocated block per request.
google::protobuf::Arena arena;
// Message + submessages + fields all come from the arena.
MyRequest* req = google::protobuf::Arena::CreateMessage<MyRequest>(&arena);
req->ParseFromString(bytes);
// ... use req ...
// No delete: the whole tree is freed when `arena` goes out of scope,
// with (usually) no per-object destructors run.

message Envelope {
  string id = 1;
  // Big, usually-present, rarely-read submessage: parse it only on access.
  Payload payload = 2 [lazy = true]; // hint; singular message fields only
}

// The classic self-describing message (from the protobuf Techniques guide).
// The descriptor_set carries the schema; the Any carries the payload.
syntax = "proto2";
import "google/protobuf/any.proto";
import "google/protobuf/descriptor.proto";

message SelfDescribingMessage {
  // Set of FileDescriptorProtos which describe the type and its dependencies.
  google.protobuf.FileDescriptorSet descriptor_set = 1;
  // The message and its type, encoded as an Any.
  google.protobuf.Any message = 2;
}

// A length-delimited stream: many messages in one file/socket.
// Each write prefixes the message with its size as a varint.
try (OutputStream out = Files.newOutputStream(path)) {
  for (Event e : events) {
    e.writeDelimitedTo(out);          // varint length + message bytes
  }
}

// Reading mirrors it: parseDelimitedFrom returns null at end-of-stream.
try (InputStream in = Files.newInputStream(path)) {
  Event e;
  while ((e = Event.parseDelimitedFrom(in)) != null) {
    handle(e);
  }
}

syntax = "proto3";
package myco;
import "google/protobuf/descriptor.proto";

// Declare custom options by EXTENDING the descriptor's option messages.
extend google.protobuf.FieldOptions {
  string sensitivity = 50001;   // 50000-99999 = safe for in-house use
}
extend google.protobuf.MessageOptions {
  bool audited = 50002;
}

message User {
  option (myco.audited) = true;                     // message-level custom option

  string id    = 1;
  string email = 2 [(myco.sensitivity) = "pii"];    // field-level custom option
  string ssn   = 3 [(myco.sensitivity) = "secret"];
}

// Read a custom option back off a field descriptor via reflection.
fd := msgDesc.Fields().ByName("email")
opts := fd.Options().(*descriptorpb.FieldOptions)
if proto.HasExtension(opts, mycopb.E_Sensitivity) {
    level := proto.GetExtension(opts, mycopb.E_Sensitivity).(string)
    // level == "pii"
}

// The entire contract of a protoc plugin: read a request from stdin,
// write a response to stdout. (protogen wraps this for you.)
func main() {
    in, _ := io.ReadAll(os.Stdin)
    var req pluginpb.CodeGeneratorRequest
    proto.Unmarshal(in, &req)

    var resp pluginpb.CodeGeneratorResponse
    for _, f := range req.GetProtoFile() {
        // ...walk descriptors, read custom options, build output...
        resp.File = append(resp.File, &pluginpb.CodeGeneratorResponse_File{
            Name:    proto.String(f.GetName() + ".myext.go"),
            Content: proto.String(generated),
        })
    }
    resp.SupportedFeatures = proto.Uint64(uint64(pluginpb.CodeGeneratorResponse_FEATURE_PROTO3_OPTIONAL))
    out, _ := proto.Marshal(&resp)
    os.Stdout.Write(out)   // exit 0 even on a reported error (set resp.Error)
}

// Validation as custom options (protovalidate): rules live in the schema,
// a runtime library reads them and checks the message — no generated code.
message Signup {
  string email = 1 [(buf.validate.field).string.email = true];
  uint32 age   = 2 [(buf.validate.field).uint32.gte = 13,
                    (buf.validate.field).uint32.lte = 150];
  string id    = 3 [(buf.validate.field).string.uuid = true];
}
